#!/bin/bash
# RNA-OmniDistill Experiment Matrix Runner
# =========================================
# Usage (run on server):
#   bash scripts/run_experiment_matrix.sh train rnacentral_drnafm_50k_seed42
#   bash scripts/run_experiment_matrix.sh bench rnacentral_drnafm_50k_seed42
#   bash scripts/run_experiment_matrix.sh summarize
#
# Requirements:
#   - Server with GPU and PyTorch
#   - RNA-OmniDiffusion repo at current directory
#   - Preprocessed datasets in dataset/processed/
#   - RNA-FM embeddings in dataset/teacher_emb/
#   - Configs generated by: python scripts/experiments.py make_configs --base config/candidate.yaml

set -euo pipefail

PYTHON="${PYTHON:-python}"
REPO_DIR="$(cd "$(dirname "$0")/.." && pwd)"
cd "$REPO_DIR"

DEVICE="${CUDA_VISIBLE_DEVICES:-0}"
export CUDA_VISIBLE_DEVICES="$DEVICE"

LOGDIR="outputs/logs"
mkdir -p "$LOGDIR"

# ─── Config registry ───
declare -A CONFIGS
CONFIGS=(
    ["baseline"]="config/candidate.yaml"
    ["rnacentral_drnafm_50k_seed42"]="config/experiments/rnacentral_drnafm_50k_seed42.yaml"
    ["rnacentral_drnafm_50k_seed43"]="config/experiments/rnacentral_drnafm_50k_seed43.yaml"
    ["rnacentral_drnafm_50k_seed44"]="config/experiments/rnacentral_drnafm_50k_seed44.yaml"
    ["rfam_donly_50k"]="config/experiments/rfam_donly_50k.yaml"
    ["rfam_drnafm_50k"]="config/experiments/rfam_drnafm_50k.yaml"
    ["bprna_drnafm_50k"]="config/experiments/bprna_drnafm_50k.yaml"
    ["rnacentral_donly_50k"]="config/experiments/rnacentral_donly_50k.yaml"
    ["rnacentral_drnafm_100k"]="config/experiments/rnacentral_drnafm_100k.yaml"
    ["norefine"]="config/experiments/norefine.yaml"
    ["refine_b2"]="config/experiments/refine_b2.yaml"
    ["refine_b3"]="config/experiments/refine_b3.yaml"
)

# ─── Output dir mapping ───
declare -A OUTDIRS
OUTDIRS=(
    ["baseline"]="outputs/runs/baseline"
    ["rnacentral_drnafm_50k_seed42"]="outputs/runs/rnacentral_drnafm_50k_seed42"
    ["rnacentral_drnafm_50k_seed43"]="outputs/runs/rnacentral_drnafm_50k_seed43"
    ["rnacentral_drnafm_50k_seed44"]="outputs/runs/rnacentral_drnafm_50k_seed44"
    ["rfam_donly_50k"]="outputs/runs/rfam_donly_50k"
    ["rfam_drnafm_50k"]="outputs/runs/rfam_drnafm_50k"
    ["bprna_drnafm_50k"]="outputs/runs/bprna_drnafm_50k"
    ["rnacentral_donly_50k"]="outputs/runs/rnacentral_donly_50k"
    ["rnacentral_drnafm_100k"]="outputs/runs/rnacentral_drnafm_100k"
    ["norefine"]="outputs/runs/norefine"
    ["refine_b2"]="outputs/runs/refine_b2"
    ["refine_b3"]="outputs/runs/refine_b3"
)

# ─── train ───
cmd_train() {
    local name="$1"
    local config="${CONFIGS[$name]}"
    local outdir="${OUTDIRS[$name]}"
    local logfile="$LOGDIR/train_${name}.log"
    
    echo "========================================="
    echo "Training: $name"
    echo "Config:   $config"
    echo "Output:   $outdir"
    echo "Log:      $logfile"
    echo "Started:  $(date)"
    echo "========================================="
    
    $PYTHON main.py train \
        --config "$config" \
        --device cuda \
        2>&1 | tee "$logfile"
    
    echo "Completed: $(date)"
}

# ─── bench ───
cmd_bench() {
    local name="$1"
    local config="${CONFIGS[$name]}"
    local outdir="${OUTDIRS[$name]}"
    local ckpt="$outdir/best.pt"
    local logfile="$LOGDIR/bench_${name}.log"
    
    if [ ! -f "$ckpt" ]; then
        echo "Error: checkpoint not found: $ckpt"
        exit 1
    fi
    
    echo "========================================="
    echo "Benchmark: $name"
    echo "Checkpoint: $ckpt"
    echo "Started:   $(date)"
    echo "========================================="
    
    $PYTHON scripts/eval.py bench \
        --config "$config" \
        --ckpt "$ckpt" \
        --split test \
        --device cuda \
        --decode nussinov \
        --stage_logits \
        --workers 8 \
        --chunksize 2 \
        --profile \
        2>&1 | tee "$logfile"
    
    echo "Completed: $(date)"
}

# ─── summarize ───
cmd_summarize() {
    echo "========================================="
    echo "Summarizing all runs"
    echo "========================================="
    
    # Collect all run directories
    local runs=""
    for name in "${!OUTDIRS[@]}"; do
        local outdir="${OUTDIRS[$name]}"
        if [ -f "$outdir/benchmark.json" ]; then
            runs="$runs $outdir"
        fi
    done
    
    if [ -z "$runs" ]; then
        echo "No benchmark results found."
        exit 0
    fi
    
    $PYTHON scripts/experiments.py summarize \
        --runs $runs \
        --out release/experiment_summary.md
    
    $PYTHON scripts/experiments.py export_table \
        --runs $runs \
        --out release/tables/main_results.csv
    
    echo "Summary written to release/experiment_summary.md"
    echo "Table written to release/tables/main_results.csv"
}

# ─── Main ───
case "${1:-}" in
    train)
        cmd_train "${2:?Usage: $0 train <experiment_name>}"
        ;;
    bench)
        cmd_bench "${2:?Usage: $0 bench <experiment_name>}"
        ;;
    summarize)
        cmd_summarize
        ;;
    all)
        echo "Running full matrix (this will take hours)..."
        for name in "${!CONFIGS[@]}"; do
            cmd_train "$name"
            cmd_bench "$name"
        done
        cmd_summarize
        ;;
    list)
        echo "Available experiments:"
        for name in "${!CONFIGS[@]}"; do
            echo "  $name -> ${CONFIGS[$name]}"
        done
        ;;
    *)
        echo "Usage: $0 {train|bench|summarize|all|list} [experiment_name]"
        echo ""
        echo "Examples:"
        echo "  $0 list"
        echo "  $0 train baseline"
        echo "  $0 bench rnacentral_drnafm_50k_seed42"
        echo "  $0 summarize"
        echo ""
        echo "Note: Run this script on the GPU server. Do NOT run locally."
        exit 1
        ;;
esac
